export type Role = 'ADMIN' | 'USER';

export interface AuthUser {
  id: string;
  name: string;
  email: string;
  role: Role;
}

export interface Account {
  id: string;
  name: string;
  industry: string;
  // The backend persists name + industry only. These UI-only fields are kept
  // optional so the approved detail layout still renders (they show as blank).
  website?: string;
  phone?: string;
  employees?: number;
}

export interface Contact {
  id: string;
  name: string;
  email: string;
  phone: string;
  accountId: string;
  accountName: string;
}

export type Stage =
  | 'Prospecting'
  | 'Qualification'
  | 'Proposal'
  | 'Negotiation'
  | 'ClosedWon'
  | 'ClosedLost';

export const STAGES: Stage[] = [
  'Prospecting',
  'Qualification',
  'Proposal',
  'Negotiation',
  'ClosedWon',
  'ClosedLost',
];

export interface Opportunity {
  id: string;
  name: string;
  amount: number;
  stage: Stage;
  accountId: string;
  accountName: string;
}

// Aligned with the backend Prisma `LeadStatus` enum.
export type LeadStatus = 'New' | 'Working' | 'Qualified' | 'Unqualified' | 'Converted';

export const LEAD_STATUSES: LeadStatus[] = [
  'New',
  'Working',
  'Qualified',
  'Unqualified',
  'Converted',
];

export interface Lead {
  id: string;
  name: string;
  // UI-only field — the backend Lead model does not persist a company.
  company: string;
  email: string;
  status: LeadStatus;
}

export type TaskStatus = 'Open' | 'Completed';

export interface CrmTask {
  id: string;
  title: string;
  dueDate: string;
  status: TaskStatus;
  relatedTo: string;
}
